import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Typography,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  IconButton,
  Button,
  Breadcrumbs,
  Link,
  CircularProgress,
} from '@mui/material';
import {
  FolderOutlined,
  InsertDriveFileOutlined,
  CreateNewFolderOutlined,
  UploadFileOutlined,
  DeleteOutline,
  ArrowUpward as ArrowUpwardIcon,
} from '@mui/icons-material';
import * as api from '../services/api';

function FilePanel({ onFileSelect, onFileClose, openFiles, activeFile }) {
  const [currentPath, setCurrentPath] = useState('');
  const [files, setFiles] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [refreshTrigger, setRefreshTrigger] = useState(0);

  const loadFiles = useCallback(async () => {
    console.log('Loading files for path:', currentPath);
    setLoading(true);
    setError(null);
    try {
      const fileList = await api.listFiles(currentPath);
      console.log('Loaded files:', fileList);
      setFiles(fileList);
    } catch (err) {
      console.error('Error loading files:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [currentPath]);

  const refresh = useCallback(() => {
    console.log('Refreshing file list');
    setRefreshTrigger(prev => prev + 1);
  }, []);

  useEffect(() => {
    loadFiles();
  }, [loadFiles, refreshTrigger]);

  useEffect(() => {
    const handleRefresh = () => refresh();
    window.addEventListener('file-list-refresh', handleRefresh);
    return () => window.removeEventListener('file-list-refresh', handleRefresh);
  }, [refresh]);

  const handleFileClick = async (file) => {
    console.log('File clicked:', file);
    if (file.type === 'directory') {
      setCurrentPath(file.path);
    } else {
      try {
        const content = await api.readFile(file.path);
        onFileSelect({
          ...file,
          content,
          language: getFileLanguage(file.name),
        });
      } catch (error) {
        console.error('Failed to read file:', error);
        setError(error.message);
      }
    }
  };

  const handleParentClick = () => {
    if (!currentPath) return;
    const parentPath = currentPath.split('/').slice(0, -1).join('/');
    setCurrentPath(parentPath);
  };

  const handleDelete = async (file) => {
    if (!window.confirm(`Are you sure you want to delete ${file.name}?`)) return;

    setLoading(true);
    try {
      await api.deleteFile(file.path);
      await loadFiles(currentPath);
    } catch (error) {
      console.error('Failed to delete:', error);
      setError(error.message);
    } finally {
      setLoading(false);
    }
  };

  const getFileLanguage = (filename) => {
    const ext = filename.split('.').pop().toLowerCase();
    const languageMap = {
      'js': 'javascript',
      'jsx': 'javascript',
      'ts': 'typescript',
      'tsx': 'typescript',
      'py': 'python',
      'java': 'java',
      'cpp': 'cpp',
      'c': 'c',
      'html': 'html',
      'css': 'css',
      'json': 'json',
      'md': 'markdown',
      'txt': 'text',
      'sh': 'shell',
      'yml': 'yaml',
      'yaml': 'yaml',
      'xml': 'xml',
      'sql': 'sql',
      'go': 'go',
      'rs': 'rust',
      'php': 'php',
      'rb': 'ruby',
    };
    return languageMap[ext] || 'plaintext';
  };

  const renderBreadcrumbs = () => {
    const paths = currentPath.split('/').filter(Boolean);
    return (
      <Breadcrumbs sx={{ mb: 2 }}>
        <Link
          component="button"
          variant="body1"
          onClick={() => setCurrentPath('')}
          sx={{ cursor: 'pointer' }}
        >
          Root
        </Link>
        {paths.map((name, index) => {
          const path = paths.slice(0, index + 1).join('/');
          return (
            <Link
              key={path}
              component="button"
              variant="body1"
              onClick={() => setCurrentPath(path)}
              sx={{ cursor: 'pointer' }}
            >
              {name}
            </Link>
          );
        })}
      </Breadcrumbs>
    );
  };

  console.log('Current path:', currentPath);
  console.log('Files:', files);

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', p: 3 }}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Box sx={{ p: 3, color: 'error.main' }}>
        <Typography>Error: {error}</Typography>
      </Box>
    );
  }

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <Box sx={{ p: 2, borderBottom: 1, borderColor: 'divider' }}>
        <Typography variant="h6" gutterBottom>
          Files
        </Typography>
        {renderBreadcrumbs()}
      </Box>

      <Box sx={{ flexGrow: 1, overflow: 'auto' }}>
        <List dense>
          {currentPath && (
            <ListItem
              button
              onClick={handleParentClick}
            >
              <ListItemIcon>
                <ArrowUpwardIcon />
              </ListItemIcon>
              <ListItemText 
                primary=".." 
                secondary="Parent Directory" 
              />
            </ListItem>
          )}
          {Array.isArray(files) && files.map((file) => (
            <ListItem
              key={file.path}
              button
              onClick={() => handleFileClick(file)}
              selected={activeFile?.path === file.path}
              secondaryAction={
                <IconButton
                  edge="end"
                  size="small"
                  onClick={(e) => {
                    e.stopPropagation();
                    handleDelete(file);
                  }}
                >
                  <DeleteOutline />
                </IconButton>
              }
            >
              <ListItemIcon>
                {file.type === 'directory' ? (
                  <FolderOutlined />
                ) : (
                  <InsertDriveFileOutlined />
                )}
              </ListItemIcon>
              <ListItemText
                primary={file.name}
                secondary={
                  file.type === 'directory'
                    ? `${file.itemCount || 0} items`
                    : `${(file.size / 1024).toFixed(1)} KB`
                }
              />
            </ListItem>
          ))}
        </List>
      </Box>
    </Box>
  );
}

export default FilePanel;
